final:
module RefModule(
  input clk, rst, set, clr, d,
  output reg q
);  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or negedge rst or posedge dbg_halt) begin
  if (~rst) begin
    q <= 1'b0;
  end else if (set) begin
    q <= 1'b1;
  end else if (clr) begin
    q <= 1'b0;
  end else begin
    q <= d;
  end
end

endmodule
